args.sparql:
SELECT ?year ?time WHERE {
  VALUES ?race { wd:Q19704270 wd:Q23045166 }  # 2015 and 2016 Canadian GP
  ?race wdt:P585 ?date ; 
         wdt:P8481 ?time .  # P8481 = "fastest qualifying time"
  BIND(YEAR(?date) AS ?year)
  FILTER(BOUND(?time))
}
ORDER BY ASC(?time)

SELECT ?race (xsd:integer(?time * 1000) AS ?timeMs)
WHERE {
  VALUES ?race { wd:Q19704270 wd:Q23045166 }
  ?race wdt:P4850 wd:Q9673 ;  # pole sitter Hamilton
        wdt:P4849 ?time .      # qualifying time in seconds
}
ORDER BY ?time

SELECT ?race ?qualifier ?val
WHERE {
  VALUES ?race { wd:Q19704270 wd:Q23045166 }
  ?race p:P3269 ?pole .
  ?pole ps:P3269 wd:Q9673 ;
        ?qualifier ?val .
}
LIMIT 10

SELECT ?race ?timeStr
WHERE {
  VALUES ?race { wd:Q19704270 wd:Q23045166 }
  ?race p:P3269 ?poleStmt .
  ?poleStmt ps:P3269 wd:Q9673 ;
            pq:P2638 ?timeStr .
}

SELECT ?timeMs
WHERE {
  VALUES ?race { wd:Q19704270 wd:Q23045166 }
  ?race p:P3269 ?stmt .
  ?stmt ps:P3269 wd:Q9673 ;
        pq:P2638 ?timeStr .
  BIND(xsd:integer(STRBEFORE(?timeStr, ":")) AS ?minutes)
  BIND(xsd:float(STRAFTER(?timeStr, ":")) AS ?seconds)
  BIND(ROUND((?minutes * 60 + ?seconds) * 1000) AS ?timeMs)
}
ORDER BY ASC(?timeMs)
OFFSET 1
LIMIT 1

SELECT (ROUND(?timeSec * 1000) AS ?timeMs)
WHERE {
  VALUES ?race { wd:Q19704270 wd:Q23045166 }  # 2015 and 2016 Canadian GP
  ?race p:P4850 ?pole ;
         wdt:P4850 wd:Q9673 .  # Pole position driver
  ?pole pq:P1855 ?timeSec .  # Time of achievement (seconds)
}
ORDER BY ASC(?timeMs)
OFFSET 1
LIMIT 1

SELECT ?race (ROUND((xsd:integer(?min) * 60 + xsd:float(?secPart)) * 1000) AS ?timeMs)
WHERE {
  VALUES ?race { wd:Q19704270 wd:Q23045166 }
  ?race p:P3269 ?poleStmt .
  ?poleStmt ps:P3269 wd:Q9673 ;
             pq:P2638 ?timeStr .
  BIND(REPLACE(?timeStr, "\\D+", " ") AS ?cleaned)
  BIND(STRAFTER(?cleaned, " ") AS ?secPart)
  BIND(STRBEFORE(?cleaned, " ") AS ?min)
}

SELECT (REPLACE(REPLACE(?timeStr, "^[^\d]+", ""), "[^\d:.]+", "") AS ?cleanTime)
WHERE {
  VALUES ?race { wd:Q19704270 wd:Q23045166 }
  ?race p:P3269 ?stmt .
  ?stmt ps:P3269 wd:Q9673 ;
        pq:P2638 ?timeStr .
}
ORDER BY ?timeStr
LIMIT 10

