SELECT ?raceLabel (ROUND(?timeSec * 1000) AS ?timeMs)
WHERE {
  VALUES ?race { wd:Q19704270 wd:Q23045166 } # 2015/2016 Canadian GP
  ?race p:P8437 ?result ;
        rdfs:label ?raceLabel .
  ?result ps:P8437 wd:Q9673 ; # Lewis Hamilton
          pq:P4849 ?timeSec ;
          pq:P5062 wd:Q419128 . # Qualifying 3
  FILTER(LANG(?raceLabel) = 'en')
}
ORDER BY ASC(?timeMs)
LIMIT 2
